import { pipe } from "effect/Function"
import type ts from "typescript"
import * as LanguageServicePluginOptions from "../core/LanguageServicePluginOptions.js"
import * as LSP from "../core/LSP.js"
import * as Nano from "../core/Nano.js"
import * as TypeCheckerApi from "../core/TypeCheckerApi.js"
import * as TypeCheckerUtils from "../core/TypeCheckerUtils.js"
import * as TypeParser from "../core/TypeParser.js"
import * as TypeScriptApi from "../core/TypeScriptApi.js"
import * as TypeScriptUtils from "../core/TypeScriptUtils.js"

type SupportedFunctionNode = ts.FunctionExpression | ts.ArrowFunction | ts.FunctionDeclaration

interface EffectFnOpportunityTarget {
  readonly node: SupportedFunctionNode
  readonly nameIdentifier: ts.Identifier | ts.StringLiteral | undefined
  readonly effectModuleName: string
  /** Suggested trace name from the function/variable name */
  readonly suggestedTraceName: string | undefined
  /** Inferred trace name from exported member/context */
  readonly inferredTraceName: string | undefined
  /** Explicit trace expression extracted from withSpan (if last pipe arg is withSpan) */
  readonly explicitTraceExpression: ts.Expression | undefined
  readonly pipeArguments: ReadonlyArray<ts.Expression>
  /** Present if the opportunity originated from an Effect.gen call */
  readonly generatorFunction: ts.FunctionExpression | undefined
  /** True if function parameters are referenced in pipe arguments (unsafe to convert) */
  readonly hasParamsInPipeArgs: boolean
}

export const effectFnOpportunity = LSP.createDiagnostic({
  name: "effectFnOpportunity",
  code: 41,
  description: "Suggests using Effect.fn for functions that returns an Effect",
  group: "style",
  severity: "suggestion",
  fixable: true,
  supportedEffect: ["v3", "v4"],
  apply: Nano.fn("effectFnOpportunity.apply")(function*(sourceFile, report) {
    const ts = yield* Nano.service(TypeScriptApi.TypeScriptApi)
    const typeChecker = yield* Nano.service(TypeCheckerApi.TypeCheckerApi)
    const typeCheckerUtils = yield* Nano.service(TypeCheckerUtils.TypeCheckerUtils)
    const typeParser = yield* Nano.service(TypeParser.TypeParser)
    const tsUtils = yield* Nano.service(TypeScriptUtils.TypeScriptUtils)
    const pluginOptions = yield* Nano.service(LanguageServicePluginOptions.LanguageServicePluginOptions)

    const sourceEffectModuleName = tsUtils.findImportedModuleIdentifierByPackageAndNameOrBarrel(
      sourceFile,
      "effect",
      "Effect"
    ) || "Effect"

    // ==================== Parsing helpers ====================

    /**
     * Finds a single return statement in a block, returning undefined if there are
     * multiple returns or complex control flow
     */
    const findSingleReturnStatement = (block: ts.Block): ts.ReturnStatement | undefined => {
      if (block.statements.length !== 1) return undefined
      const statement = block.statements[0]
      if (!ts.isReturnStatement(statement)) return undefined
      return statement
    }

    /**
     * Gets the body expression from a function node.
     * For block bodies, requires a single return statement.
     */
    const getBodyExpression = (fnNode: SupportedFunctionNode): ts.Expression | undefined => {
      if (ts.isArrowFunction(fnNode)) {
        if (ts.isBlock(fnNode.body)) {
          return findSingleReturnStatement(fnNode.body)?.expression
        }
        return fnNode.body
      } else if ((ts.isFunctionExpression(fnNode) || ts.isFunctionDeclaration(fnNode)) && fnNode.body) {
        return findSingleReturnStatement(fnNode.body)?.expression
      }
      return undefined
    }

    /**
     * Gets the name identifier node from the context (variable name or function declaration name)
     */
    const getNameIdentifier = (
      node: SupportedFunctionNode
    ): ts.Identifier | ts.StringLiteral | undefined => {
      if (ts.isFunctionDeclaration(node) && node.name) {
        return node.name
      }
      if (
        node.parent && ts.isVariableDeclaration(node.parent) && ts.isIdentifier(node.parent.name) &&
        node.parent.initializer === node
      ) {
        return node.parent.name
      }
      if (node.parent && ts.isPropertyAssignment(node.parent) && node.parent.initializer === node) {
        const name = node.parent.name
        if (ts.isIdentifier(name) || ts.isStringLiteral(name)) {
          return name
        }
      }
      if (node.parent && ts.isPropertyDeclaration(node.parent) && node.parent.initializer === node) {
        const name = node.parent.name
        if (ts.isIdentifier(name)) {
          return name
        }
      }
      return undefined
    }

    const hasExportModifier = (node: ts.Node): boolean => {
      if (!ts.canHaveModifiers(node)) return false
      const modifiers = ts.getModifiers(node)
      return modifiers?.some((modifier) => modifier.kind === ts.SyntaxKind.ExportKeyword) ?? false
    }

    const layerServiceNameFromExpression = (expression: ts.Expression): string | undefined => {
      if (expression.kind === ts.SyntaxKind.ThisKeyword) {
        const enclosingClass = ts.findAncestor(
          expression,
          (node): node is ts.ClassDeclaration => ts.isClassDeclaration(node)
        )
        if (enclosingClass?.name) {
          return ts.idText(enclosingClass.name)
        }
      }
      if (ts.isIdentifier(expression)) return ts.idText(expression)
      return sourceFile.text.slice(expression.pos, expression.end).trim()
    }

    const tryGetLayerApiMethod = (
      node: ts.Node
    ): Nano.Nano<"effect" | "succeed" | "sync" | undefined, never, never> =>
      pipe(
        typeParser.isNodeReferenceToEffectLayerModuleApi("effect")(node),
        Nano.map(() => "effect" as const),
        Nano.orElse(() =>
          pipe(
            typeParser.isNodeReferenceToEffectLayerModuleApi("succeed")(node),
            Nano.map(() => "succeed" as const),
            Nano.orElse(() =>
              pipe(
                typeParser.isNodeReferenceToEffectLayerModuleApi("sync")(node),
                Nano.map(() => "sync" as const),
                Nano.orElse(() => Nano.succeed(undefined))
              )
            )
          )
        )
      )

    const verifyLayerMethodAtCall: (
      callExpression: ts.CallExpression,
      method: "effect" | "succeed" | "sync",
      implementationExpression: ts.Expression
    ) => Nano.Nano<string | undefined, never, never> = Nano.fn("effectFnOpportunity.verifyLayerMethodAtCall")(
      function*(
        callExpression: ts.CallExpression,
        method: "effect" | "succeed" | "sync",
        implementationExpression: ts.Expression
      ) {
        const directMethod = yield* tryGetLayerApiMethod(callExpression.expression)
        if (
          directMethod === method && callExpression.arguments.length >= 2 &&
          callExpression.arguments[1] === implementationExpression
        ) {
          return layerServiceNameFromExpression(callExpression.arguments[0])
        }
        if (ts.isCallExpression(callExpression.expression)) {
          const innerCall = callExpression.expression
          const innerMethod = yield* tryGetLayerApiMethod(innerCall.expression)
          if (
            innerMethod === method && innerCall.arguments.length >= 1 && callExpression.arguments.length >= 1 &&
            callExpression.arguments[0] === implementationExpression
          ) {
            return layerServiceNameFromExpression(innerCall.arguments[0])
          }
        }
        return undefined
      }
    )

    const tryMatchLayerSucceedInference: (
      objectLiteral: ts.ObjectLiteralExpression
    ) => Nano.Nano<string | undefined, never, never> = Nano.fn("effectFnOpportunity.tryMatchLayerSucceedInference")(
      function*(objectLiteral: ts.ObjectLiteralExpression) {
        const callExpression = objectLiteral.parent
        if (!callExpression || !ts.isCallExpression(callExpression)) return undefined
        return yield* verifyLayerMethodAtCall(callExpression, "succeed", objectLiteral)
      }
    )

    const tryMatchLayerSyncInference: (
      objectLiteral: ts.ObjectLiteralExpression
    ) => Nano.Nano<string | undefined, never, never> = Nano.fn("effectFnOpportunity.tryMatchLayerSyncInference")(
      function*(objectLiteral: ts.ObjectLiteralExpression) {
        const returnStatement = objectLiteral.parent
        if (!returnStatement || !ts.isReturnStatement(returnStatement)) return undefined
        const functionBody = returnStatement.parent
        if (!functionBody || !ts.isBlock(functionBody)) return undefined
        const lazyFunction = functionBody.parent
        if (!lazyFunction || (!ts.isArrowFunction(lazyFunction) && !ts.isFunctionExpression(lazyFunction))) {
          return undefined
        }
        const callExpression = lazyFunction.parent
        if (!callExpression || !ts.isCallExpression(callExpression)) return undefined
        return yield* verifyLayerMethodAtCall(callExpression, "sync", lazyFunction)
      }
    )

    const tryMatchLayerEffectInference: (
      objectLiteral: ts.ObjectLiteralExpression
    ) => Nano.Nano<string | undefined, never, never> = Nano.fn("effectFnOpportunity.tryMatchLayerEffectInference")(
      function*(objectLiteral: ts.ObjectLiteralExpression) {
        const returnStatement = objectLiteral.parent
        if (!returnStatement || !ts.isReturnStatement(returnStatement)) return undefined
        const generatorBody = returnStatement.parent
        if (!generatorBody || !ts.isBlock(generatorBody)) return undefined
        const generatorFunction = generatorBody.parent
        if (!generatorFunction || !ts.isFunctionExpression(generatorFunction) || !generatorFunction.asteriskToken) {
          return undefined
        }
        const genCall = generatorFunction.parent
        if (!genCall || !ts.isCallExpression(genCall)) return undefined
        const parsedEffectGen = yield* Nano.option(typeParser.effectGen(genCall))
        if (parsedEffectGen._tag === "None" || parsedEffectGen.value.generatorFunction !== generatorFunction) {
          return undefined
        }
        const layerCall = genCall.parent
        if (!layerCall || !ts.isCallExpression(layerCall)) return undefined
        return yield* verifyLayerMethodAtCall(layerCall, "effect", genCall)
      }
    )

    const tryMatchOfInference: (
      objectLiteral: ts.ObjectLiteralExpression
    ) => Nano.Nano<string | undefined, never, never> = Nano.fn("effectFnOpportunity.tryMatchOfInference")(
      function*(objectLiteral: ts.ObjectLiteralExpression) {
        const callExpression = objectLiteral.parent
        if (!callExpression || !ts.isCallExpression(callExpression)) return undefined
        if (callExpression.arguments.length < 1 || callExpression.arguments[0] !== objectLiteral) return undefined
        if (!ts.isPropertyAccessExpression(callExpression.expression)) return undefined
        if (ts.idText(callExpression.expression.name) !== "of") return undefined

        const serviceTagExpression = callExpression.expression.expression
        const serviceTagType = typeCheckerUtils.getTypeAtLocation(serviceTagExpression)
        if (!serviceTagType) return undefined

        const isTagLike = yield* pipe(
          typeParser.contextTag(serviceTagType, serviceTagExpression),
          Nano.orElse(() => typeParser.serviceType(serviceTagType, serviceTagExpression)),
          Nano.option
        )
        if (isTagLike._tag === "None") return undefined

        return layerServiceNameFromExpression(serviceTagExpression)
      }
    )

    const tryMatchContextMakeInference: (
      objectLiteral: ts.ObjectLiteralExpression
    ) => Nano.Nano<string | undefined, never, never> = Nano.fn("effectFnOpportunity.tryMatchContextMakeInference")(
      function*(objectLiteral: ts.ObjectLiteralExpression) {
        const returnStatement = objectLiteral.parent
        if (!returnStatement || !ts.isReturnStatement(returnStatement)) return undefined
        const generatorBody = returnStatement.parent
        if (!generatorBody || !ts.isBlock(generatorBody)) return undefined
        const generatorFunction = generatorBody.parent
        if (!generatorFunction || !ts.isFunctionExpression(generatorFunction) || !generatorFunction.asteriskToken) {
          return undefined
        }
        const genCall = generatorFunction.parent
        if (!genCall || !ts.isCallExpression(genCall)) return undefined
        const parsedEffectGen = yield* Nano.option(typeParser.effectGen(genCall))
        if (parsedEffectGen._tag === "None" || parsedEffectGen.value.generatorFunction !== generatorFunction) {
          return undefined
        }

        const makeProperty = genCall.parent
        if (!makeProperty || !ts.isPropertyAssignment(makeProperty)) return undefined
        if (makeProperty.initializer !== genCall) return undefined
        if (!ts.isIdentifier(makeProperty.name) || ts.idText(makeProperty.name) !== "make") return undefined

        let currentNode: ts.Node | undefined = makeProperty.parent
        let classDeclaration: ts.ClassDeclaration | undefined = undefined
        while (currentNode) {
          if (ts.isClassDeclaration(currentNode)) {
            classDeclaration = currentNode
            break
          }
          currentNode = currentNode.parent
        }
        if (!classDeclaration || !classDeclaration.name) return undefined

        const parsedContextService = yield* Nano.orUndefined(typeParser.extendsContextService(classDeclaration))
        if (!parsedContextService) return undefined

        return ts.idText(classDeclaration.name)
      }
    )

    /**
     * Gets a strict inferred trace name from layer pattern suspects.
     */
    const tryGetLayerInferredTraceName: (
      node: SupportedFunctionNode,
      suggestedTraceName: string | undefined
    ) => Nano.Nano<string | undefined, never, never> = Nano.fn("effectFnOpportunity.tryGetLayerInferredTraceName")(
      function*(node: SupportedFunctionNode, suggestedTraceName: string | undefined) {
        if (!suggestedTraceName) return undefined
        if (
          !(
            node.parent &&
            ts.isPropertyAssignment(node.parent) &&
            node.parent.initializer === node &&
            node.parent.parent &&
            ts.isObjectLiteralExpression(node.parent.parent)
          )
        ) {
          return undefined
        }

        const objectLiteral = node.parent.parent
        const succeedServiceName = yield* tryMatchLayerSucceedInference(objectLiteral)
        if (succeedServiceName) return `${succeedServiceName}.${suggestedTraceName}`

        const syncServiceName = yield* tryMatchLayerSyncInference(objectLiteral)
        if (syncServiceName) return `${syncServiceName}.${suggestedTraceName}`

        const effectServiceName = yield* tryMatchLayerEffectInference(objectLiteral)
        if (effectServiceName) return `${effectServiceName}.${suggestedTraceName}`

        const ofServiceName = yield* tryMatchOfInference(objectLiteral)
        if (ofServiceName) return `${ofServiceName}.${suggestedTraceName}`

        const contextMakeServiceName = yield* tryMatchContextMakeInference(objectLiteral)
        return contextMakeServiceName ? `${contextMakeServiceName}.${suggestedTraceName}` : undefined
      }
    )

    /**
     * Gets an inferred trace name from strict contexts:
     * - Layer service implementation members (ServiceTag.memberName)
     * - exported declarations (function declarations or exported const initializers)
     */
    const getInferredTraceName: (
      node: SupportedFunctionNode,
      suggestedTraceName: string | undefined
    ) => Nano.Nano<string | undefined, never, never> = Nano.fn("effectFnOpportunity.getInferredTraceName")(
      function*(node: SupportedFunctionNode, suggestedTraceName: string | undefined) {
        const inferredFromLayer = yield* tryGetLayerInferredTraceName(node, suggestedTraceName)
        if (inferredFromLayer) return inferredFromLayer

        if (ts.isFunctionDeclaration(node) && node.name && hasExportModifier(node)) {
          return ts.idText(node.name)
        }

        if (
          node.parent && ts.isVariableDeclaration(node.parent) && ts.isIdentifier(node.parent.name) &&
          node.parent.initializer === node
        ) {
          const variableDeclarationList = node.parent.parent
          const variableStatement = variableDeclarationList?.parent
          if (
            variableDeclarationList && ts.isVariableDeclarationList(variableDeclarationList) &&
            variableStatement && ts.isVariableStatement(variableStatement) &&
            hasExportModifier(variableStatement) &&
            (variableDeclarationList.flags & ts.NodeFlags.Const) !== 0
          ) {
            return ts.idText(node.parent.name)
          }
        }

        return undefined
      }
    )

    interface ParsedOpportunity {
      readonly effectModuleName: string
      readonly pipeArguments: ReadonlyArray<ts.Expression>
      readonly generatorFunction: ts.FunctionExpression | undefined
      /** Explicit trace expression extracted from withSpan (if last pipe arg is withSpan) */
      readonly explicitTraceExpression: ts.Expression | undefined
    }

    /**
     * Checks if any of the function's parameter symbols are referenced within the given nodes.
     * Uses declaration position checking: if a symbol's declaration is within the function's
     * parameters range, it's a parameter reference.
     */
    const areParametersReferencedIn = (
      fnNode: SupportedFunctionNode,
      nodes: ReadonlyArray<ts.Node>
    ): boolean => {
      if (fnNode.parameters.length === 0 || nodes.length === 0) return false

      // Get the position range of all parameters
      const firstParam = fnNode.parameters[0]
      const lastParam = fnNode.parameters[fnNode.parameters.length - 1]
      const paramsStart = firstParam.pos
      const paramsEnd = lastParam.end

      // Check if a symbol's declaration is within the parameters range
      const isSymbolDeclaredInParams = (symbol: ts.Symbol): boolean => {
        const declarations = symbol.declarations
        if (!declarations) return false
        return declarations.some((decl) => decl.pos >= paramsStart && decl.end <= paramsEnd)
      }

      // Walk all nodes looking for symbols declared in the function parameters
      const nodesToVisit: Array<ts.Node> = [...nodes]
      while (nodesToVisit.length > 0) {
        const node = nodesToVisit.shift()!

        // Check regular identifiers
        if (ts.isIdentifier(node)) {
          const symbol = typeChecker.getSymbolAtLocation(node)
          if (symbol && isSymbolDeclaredInParams(symbol)) {
            return true
          }
        }

        // Check shorthand property assignments like { a, b }
        if (ts.isShorthandPropertyAssignment(node)) {
          const valueSymbol = typeChecker.getShorthandAssignmentValueSymbol(node)
          if (valueSymbol && isSymbolDeclaredInParams(valueSymbol)) {
            return true
          }
        }

        ts.forEachChild(node, (child) => {
          nodesToVisit.push(child)
          return undefined
        })
      }

      return false
    }

    /**
     * Checks if an expression is a call to Effect.withSpan and extracts the span name expression.
     * Returns the span name expression if it's a withSpan call, undefined otherwise.
     */
    const tryExtractWithSpanExpression: (expr: ts.Expression) => Nano.Nano<ts.Expression | undefined, never, never> =
      Nano.fn("effectFnOpportunity.tryExtractWithSpanExpression")(function*(expr: ts.Expression) {
        // Check if it's a call expression
        if (!ts.isCallExpression(expr)) return undefined

        // Check if the callee is Effect.withSpan
        const callee = expr.expression
        const isWithSpan = yield* pipe(
          typeParser.isNodeReferenceToEffectModuleApi("withSpan")(callee),
          Nano.map(() => true),
          Nano.orElse(() => Nano.succeed(false))
        )

        if (!isWithSpan) return undefined

        // withSpan has at least one argument (the span name)
        if (expr.arguments.length === 0) return undefined

        return expr.arguments[0]
      })

    /**
     * Tries to parse a function as a Gen opportunity (returning Effect.gen with a single return statement).
     */
    const tryParseGenOpportunity: (
      fnNode: SupportedFunctionNode
    ) => Nano.Nano<ParsedOpportunity, TypeParser.TypeParserIssue, never> = Nano.fn(
      "effectFnOpportunity.tryParseGenOpportunity"
    )(function*(fnNode: SupportedFunctionNode) {
      const bodyExpression = getBodyExpression(fnNode)
      if (!bodyExpression) return yield* TypeParser.TypeParserIssue.issue

      const { pipeArguments, subject } = yield* pipe(
        typeParser.pipeCall(bodyExpression),
        Nano.map(({ args, subject }) => ({ subject, pipeArguments: args })),
        Nano.orElse(() => Nano.succeed({ subject: bodyExpression, pipeArguments: [] as Array<ts.Expression> }))
      )

      const { effectModule, generatorFunction } = yield* typeParser.effectGen(subject)

      const effectModuleName = ts.isIdentifier(effectModule)
        ? ts.idText(effectModule)
        : sourceEffectModuleName

      // Check if the last pipe argument is Effect.withSpan and extract the span name
      // We keep all pipe arguments intact here; the autofix will remove withSpan when needed
      let explicitTraceExpression: ts.Expression | undefined

      if (pipeArguments.length > 0) {
        const lastArg = pipeArguments[pipeArguments.length - 1]
        const withSpanExpr = yield* tryExtractWithSpanExpression(lastArg)
        if (withSpanExpr) {
          explicitTraceExpression = withSpanExpr
        }
      }

      return { effectModuleName, generatorFunction, pipeArguments, explicitTraceExpression }
    })

    /**
     * Checks if a function node is already inside an Effect.fn or Effect.fnUntraced call.
     */
    const isInsideEffectFn = (fnNode: ts.Node): Nano.Nano<boolean, never, never> => {
      const parent = fnNode.parent
      if (!parent || !ts.isCallExpression(parent)) {
        return Nano.succeed(false)
      }
      if (parent.arguments[0] !== fnNode) {
        return Nano.succeed(false)
      }
      return pipe(
        typeParser.effectFn(parent),
        Nano.orElse(() => typeParser.effectFnGen(parent)),
        Nano.orElse(() => typeParser.effectFnUntracedGen(parent)),
        Nano.map(() => true),
        Nano.orElse(() => Nano.succeed(false))
      )
    }

    const parseEffectFnOpportunityTargetGen = Nano.fn("effectFnOpportunity.parseEffectFnOpportunityTarget")(
      function*(
        node: SupportedFunctionNode,
        returnType: ts.Type,
        nameIdentifier: ts.Identifier | ts.StringLiteral | undefined
      ) {
        const suggestedTraceName = nameIdentifier
          ? ts.isIdentifier(nameIdentifier) ? ts.idText(nameIdentifier) : nameIdentifier.text
          : undefined
        const inferredTraceName = yield* getInferredTraceName(node, suggestedTraceName)
        const hasStrictLayerInferredName = inferredTraceName !== undefined && inferredTraceName !== suggestedTraceName

        // Check if this function is already inside an Effect.fn call
        if (yield* isInsideEffectFn(node)) {
          return yield* TypeParser.TypeParserIssue.issue
        }

        // Unroll union members and check that ALL are strict Effect types
        const unionMembers = typeCheckerUtils.unrollUnionMembers(returnType)
        yield* Nano.all(...unionMembers.map((member) => typeParser.strictEffectType(member, node)))

        // Try to parse as Gen opportunity, then fall back to Regular opportunity
        // For regular functions (not Effect.gen), only suggest if:
        // - Not an arrow function with concise body (expression body)
        // - Has a block body with more than 5 statements
        const opportunity = yield* pipe(
          tryParseGenOpportunity(node),
          Nano.orElse(() => {
            // Skip arrow functions with concise body (expression body, no braces)
            if (ts.isArrowFunction(node) && !ts.isBlock(node.body) && !hasStrictLayerInferredName) {
              return TypeParser.TypeParserIssue.issue
            }
            // For functions with a block body, only suggest if there are more than 5 statements
            const body = ts.isArrowFunction(node) ? node.body as ts.Block : node.body
            if (
              (!body || !ts.isBlock(body) || body.statements.length <= 5) &&
              !hasStrictLayerInferredName
            ) {
              return TypeParser.TypeParserIssue.issue
            }
            return Nano.succeed({
              effectModuleName: sourceEffectModuleName,
              pipeArguments: [],
              generatorFunction: undefined,
              explicitTraceExpression: undefined
            })
          })
        )

        return {
          node,
          nameIdentifier,
          effectModuleName: opportunity.effectModuleName,
          inferredTraceName,
          suggestedTraceName,
          explicitTraceExpression: opportunity.explicitTraceExpression,
          pipeArguments: opportunity.pipeArguments,
          generatorFunction: opportunity.generatorFunction,
          hasParamsInPipeArgs: areParametersReferencedIn(node, opportunity.pipeArguments)
        }
      }
    )

    /**
     * Parses a node as an Effect.fn opportunity target.
     */
    const parseEffectFnOpportunityTarget = (
      node: ts.Node
    ): undefined | Nano.Nano<EffectFnOpportunityTarget, TypeParser.TypeParserIssue, never> => {
      // We're looking for function expressions, arrow functions, or function declarations
      if (!ts.isFunctionExpression(node) && !ts.isArrowFunction(node) && !ts.isFunctionDeclaration(node)) {
        return
      }

      // Skip generator functions (they can't be converted)
      if ((ts.isFunctionExpression(node) || ts.isFunctionDeclaration(node)) && node.asteriskToken) {
        return
      }

      // Skip named function expressions (they are typically used for recursion)
      if (ts.isFunctionExpression(node) && node.name) {
        return
      }

      // Skip functions with return type annotations (they could be recursive)
      if (node.type) {
        return
      }

      // Get the type of the function to check call signatures
      const functionType = typeChecker.getTypeAtLocation(node)
      if (!functionType) return

      // Check if the function has only one call signature (no overloads)
      const callSignatures = typeChecker.getSignaturesOfType(functionType, ts.SignatureKind.Call)
      if (callSignatures.length !== 1) return

      // Get the return type of the function
      const signature = callSignatures[0]
      const returnType = typeChecker.getReturnTypeOfSignature(signature)

      // Try to get a name identifier and trace name
      const nameIdentifier = getNameIdentifier(node)
      if (!nameIdentifier) return

      return parseEffectFnOpportunityTargetGen(node, returnType, nameIdentifier)
    }

    // ==================== Fix creation helpers ====================

    /**
     * Gets the function body as a Block
     */
    const getFunctionBodyBlock = (
      node: ts.FunctionExpression | ts.ArrowFunction | ts.FunctionDeclaration
    ): ts.Block => {
      if (ts.isArrowFunction(node)) {
        if (ts.isBlock(node.body)) {
          return node.body
        }
        return ts.factory.createBlock([ts.factory.createReturnStatement(node.body)], true)
      }
      return node.body!
    }

    /**
     * Checks if a function node is a generator (has asterisk token)
     */
    const isGeneratorFunction = (node: ts.FunctionExpression | ts.ArrowFunction | ts.FunctionDeclaration): boolean => {
      if (ts.isArrowFunction(node)) return false
      return node.asteriskToken !== undefined
    }

    /**
     * Creates the Effect.fn node for both Gen and Regular opportunities.
     * @param traceNameOrExpression - Either an inferred string trace name or an explicit expression from withSpan
     */
    const createEffectFnNode = (
      originalNode: SupportedFunctionNode,
      innerFunction: ts.FunctionExpression | ts.ArrowFunction | ts.FunctionDeclaration,
      effectModuleName: string,
      traceNameOrExpression: string | ts.Expression | undefined,
      pipeArguments: ReadonlyArray<ts.Expression>
    ): ts.Node => {
      const isGenerator = isGeneratorFunction(innerFunction)
      const newFunction = ts.factory.createFunctionExpression(
        undefined,
        isGenerator ? ts.factory.createToken(ts.SyntaxKind.AsteriskToken) : undefined,
        undefined,
        originalNode.typeParameters,
        originalNode.parameters,
        undefined,
        getFunctionBodyBlock(innerFunction)
      )

      let fnExpression: ts.Expression = ts.factory.createPropertyAccessExpression(
        ts.factory.createIdentifier(effectModuleName),
        "fn"
      )

      if (traceNameOrExpression) {
        // If it's a string, create a string literal; otherwise use the expression directly
        const traceArg = typeof traceNameOrExpression === "string"
          ? ts.factory.createStringLiteral(traceNameOrExpression)
          : traceNameOrExpression

        fnExpression = ts.factory.createCallExpression(
          fnExpression,
          undefined,
          [traceArg]
        )
      }

      const effectFnCall = ts.factory.createCallExpression(fnExpression, undefined, [newFunction, ...pipeArguments])

      if (ts.isFunctionDeclaration(originalNode)) {
        return tsUtils.tryPreserveDeclarationSemantics(originalNode, effectFnCall, false)
      }

      return effectFnCall
    }

    /**
     * Creates the Effect.fnUntraced node for both Gen and Regular opportunities
     */
    const createEffectFnUntracedNode = (
      originalNode: SupportedFunctionNode,
      innerFunction: ts.FunctionExpression | ts.ArrowFunction | ts.FunctionDeclaration,
      effectModuleName: string,
      pipeArguments: ReadonlyArray<ts.Expression>
    ): ts.Node => {
      const isGenerator = isGeneratorFunction(innerFunction)
      const newFunction = ts.factory.createFunctionExpression(
        undefined,
        isGenerator ? ts.factory.createToken(ts.SyntaxKind.AsteriskToken) : undefined,
        undefined,
        originalNode.typeParameters,
        originalNode.parameters,
        undefined,
        getFunctionBodyBlock(innerFunction)
      )

      const effectFnCall = ts.factory.createCallExpression(
        ts.factory.createPropertyAccessExpression(ts.factory.createIdentifier(effectModuleName), "fnUntraced"),
        undefined,
        [newFunction, ...pipeArguments]
      )

      if (ts.isFunctionDeclaration(originalNode)) {
        return tsUtils.tryPreserveDeclarationSemantics(originalNode, effectFnCall, false)
      }

      return effectFnCall
    }

    // ==================== Main visitor loop ====================

    const nodeToVisit: Array<ts.Node> = []
    const appendNodeToVisit = (node: ts.Node) => {
      nodeToVisit.push(node)
      return undefined
    }
    ts.forEachChild(sourceFile, appendNodeToVisit)

    while (nodeToVisit.length > 0) {
      const node = nodeToVisit.shift()!
      ts.forEachChild(node, appendNodeToVisit)

      const test = parseEffectFnOpportunityTarget(node)
      if (!test) continue
      const target = yield* Nano.orUndefined(test)
      if (!target) continue

      // Skip if function parameters are referenced in pipe arguments
      // (unsafe to convert - parameters wouldn't be in scope after transformation)
      if (target.hasParamsInPipeArgs) continue

      const {
        effectModuleName,
        explicitTraceExpression,
        inferredTraceName,
        nameIdentifier,
        node: targetNode,
        pipeArguments,
        suggestedTraceName
      } = target
      const innerFunction = target.generatorFunction ?? targetNode

      const fixes: Array<LSP.ApplicableDiagnosticDefinitionFix> = []

      // toEffectFnWithSpan: available when we have explicit span from withSpan
      if (pluginOptions.effectFn.includes("span") && explicitTraceExpression) {
        fixes.push({
          fixName: "effectFnOpportunity_toEffectFnWithSpan",
          description: "Convert to Effect.fn (with span from withSpan)",
          apply: Nano.gen(function*() {
            const changeTracker = yield* Nano.service(TypeScriptApi.ChangeTracker)
            // Remove the withSpan from pipe args since Effect.fn adds the span
            const finalPipeArguments = pipeArguments.slice(0, -1)
            const newNode = createEffectFnNode(
              targetNode,
              innerFunction,
              effectModuleName,
              explicitTraceExpression,
              finalPipeArguments
            )
            changeTracker.replaceNode(sourceFile, targetNode, newNode)
          })
        })
      }

      // toEffectFnUntraced: available when we have a generator function
      // Keeps ALL pipe arguments including withSpan since fnUntraced doesn't add tracing
      if (pluginOptions.effectFn.includes("untraced") && target.generatorFunction) {
        fixes.push({
          fixName: "effectFnOpportunity_toEffectFnUntraced",
          description: "Convert to Effect.fnUntraced",
          apply: Nano.gen(function*() {
            const changeTracker = yield* Nano.service(TypeScriptApi.ChangeTracker)
            const newNode = createEffectFnUntracedNode(targetNode, innerFunction, effectModuleName, pipeArguments)
            changeTracker.replaceNode(sourceFile, targetNode, newNode)
          })
        })
      }

      if (pluginOptions.effectFn.includes("no-span")) {
        // toEffectFnNoSpan: available always
        fixes.push({
          fixName: "effectFnOpportunity_toEffectFnNoSpan",
          description: "Convert to Effect.fn (no span)",
          apply: Nano.gen(function*() {
            const changeTracker = yield* Nano.service(TypeScriptApi.ChangeTracker)
            const newNode = createEffectFnNode(targetNode, innerFunction, effectModuleName, undefined, pipeArguments)
            changeTracker.replaceNode(sourceFile, targetNode, newNode)
          })
        })
      }

      // toEffectFnSpanInferred: available if we have strict inferred span name AND no explicit one
      if (!explicitTraceExpression) {
        if (pluginOptions.effectFn.includes("inferred-span") && inferredTraceName) {
          fixes.push({
            fixName: "effectFnOpportunity_toEffectFnSpanInferred",
            description: `Convert to Effect.fn("${inferredTraceName}")`,
            apply: Nano.gen(function*() {
              const changeTracker = yield* Nano.service(TypeScriptApi.ChangeTracker)
              const newNode = createEffectFnNode(
                targetNode,
                innerFunction,
                effectModuleName,
                inferredTraceName,
                pipeArguments
              )
              changeTracker.replaceNode(sourceFile, targetNode, newNode)
            })
          })
        }

        // toEffectFnSpanSuggested: broad suggestion based on local naming context
        if (
          pluginOptions.effectFn.includes("suggested-span") &&
          suggestedTraceName &&
          (!pluginOptions.effectFn.includes("inferred-span") || suggestedTraceName !== inferredTraceName)
        ) {
          fixes.push({
            fixName: "effectFnOpportunity_toEffectFnSpanSuggested",
            description: `Convert to Effect.fn("${suggestedTraceName}")`,
            apply: Nano.gen(function*() {
              const changeTracker = yield* Nano.service(TypeScriptApi.ChangeTracker)
              const newNode = createEffectFnNode(
                targetNode,
                innerFunction,
                effectModuleName,
                suggestedTraceName,
                pipeArguments
              )
              changeTracker.replaceNode(sourceFile, targetNode, newNode)
            })
          })
        }
      }

      // no fix, continue
      if (fixes.length === 0) continue

      // Generate the expected signature based on the first (recommended) fix
      const generateExpectedSignature = (): string => {
        const firstFix = fixes[0]
        if (!firstFix) return "Effect.fn(function*() { ... })"

        // Extract type parameter names from the original function
        const typeParamNames = targetNode.typeParameters
          ? `<${targetNode.typeParameters.map((tp) => ts.idText(tp.name)).join(", ")}>`
          : ""

        // Extract parameter names from the original function
        const paramNames = targetNode.parameters.map((param) => {
          if (ts.isIdentifier(param.name)) {
            return ts.idText(param.name)
          }
          // For destructuring patterns, just use a placeholder
          return "_"
        }).join(", ")

        const fnSignature = ts.isArrowFunction(innerFunction)
          ? `${typeParamNames}(${paramNames}) => { ... }`
          : isGeneratorFunction(innerFunction)
          ? `function*${typeParamNames}(${paramNames}) { ... }`
          : `function${typeParamNames}(${paramNames}) { ... }`
        const pipeArgsForWithSpan = pipeArguments.slice(0, -1)
        const pipeArgsSuffix = (args: ReadonlyArray<ts.Expression>) => args.length > 0 ? ", ...pipeTransformations" : ""

        switch (firstFix.fixName) {
          case "effectFnOpportunity_toEffectFnWithSpan": {
            const traceName = explicitTraceExpression
              ? sourceFile.text.slice(explicitTraceExpression.pos, explicitTraceExpression.end).trim()
              : undefined
            return `${effectModuleName}.fn(${traceName})(${fnSignature}${pipeArgsSuffix(pipeArgsForWithSpan)})`
          }
          case "effectFnOpportunity_toEffectFnUntraced":
            return `${effectModuleName}.fnUntraced(${fnSignature}${pipeArgsSuffix(pipeArguments)})`
          case "effectFnOpportunity_toEffectFnNoSpan":
            return `${effectModuleName}.fn(${fnSignature}${pipeArgsSuffix(pipeArguments)})`
          case "effectFnOpportunity_toEffectFnSpanInferred":
            return `${effectModuleName}.fn("${inferredTraceName}")(${fnSignature}${pipeArgsSuffix(pipeArguments)})`
          case "effectFnOpportunity_toEffectFnSpanSuggested":
            return `${effectModuleName}.fn("${suggestedTraceName}")(${fnSignature}${pipeArgsSuffix(pipeArguments)})`
          default:
            return `${effectModuleName}.fn(${fnSignature})`
        }
      }

      const expectedSignature = generateExpectedSignature()

      report({
        location: nameIdentifier ?? targetNode,
        messageText: `This expression can be rewritten in the reusable function form \`${expectedSignature}\`.`,
        fixes
      })
    }
  })
})
